89	class CoreApi {
90	public:
91	    static constexpr uint64_t FAKE_LOAD_BEGIN = 0x100000;
92	
93	    static bool IsReady();
94	    static bool Load(const char* corefile, std::function<void ()> callback);
95	    static bool Load(const char* corefile, bool remote, std::function<void ()> callback);
96	    static bool Load(std::unique_ptr<MemoryMap>& map, bool remote, std::function<void ()> callback);
97	    static void UnLoad() { INSTANCE.reset(); }
98	    static uint64_t GetBegin() { return INSTANCE->begin(); }
99	    static uint64_t GetDebugPtr() { return INSTANCE->r_debug_ptr().Ptr(); }
100	    static const char* GetName();
101	    static const char* GetMachineName();
102	    static int GetMachine();
103	    static int Bits() { return INSTANCE->bits(); }
104	    static int GetPointSize();
105	    static uint64_t GetPointMask();
106	    static uint64_t GetVabitsMask();
107	    static uint64_t GetPageSize() { return INSTANCE->getPageSize(); }
108	    static bool IsRemote() { return IsReady() && INSTANCE->isRemote(); }
109	    static std::vector<std::shared_ptr<LoadBlock>>& GetLoads(bool quick) {
110	        return INSTANCE->getLoads(quick);
111	    }
112	    static std::vector<std::unique_ptr<NoteBlock>>& GetNotes() {
113	        return INSTANCE->getNotes();
114	    }
115	    static std::vector<std::unique_ptr<LinkMap>>& GetLinkMaps() {
116	        return INSTANCE->mLinkMap;
117	    }
118	    static uint64_t GetReal(uint64_t vaddr) {
119	        return GetReal(vaddr, OPT_READ_ALL);
120	    }
121	    static uint64_t GetReal(uint64_t vaddr, int opt);
122	    static uint64_t GetVirtual(uint64_t raddr);
123	    static bool IsVirtualValid(uint64_t vaddr);
124	    static uint64_t FindAuxv(uint64_t type);
125	    static ThreadApi* FindThread(int tid);
126	    static void Init();
127	    static void Dump();
128	    static void CleanCache();
129	    static void ForeachFile(std::function<bool (File *)> callback);
130	    static void ForeachAuxv(std::function<bool (Auxv *)> callback);
131	    static void ForeachLinkMap(std::function<bool (LinkMap *)> callback);
132	    static File* FindFile(uint64_t vaddr);
133	    static LinkMap* FindLinkMap(const char* path);
134	    static void ExecFile(const char* file);
135	    static void SysRoot(const char* dir);
136	    static void Write(uint64_t vaddr, uint64_t value) {
137	        Write(vaddr, &value, 8);
138	    }
139	    static void Write(uint64_t vaddr, void *buf, uint64_t size);
140	    static bool Read(uint64_t vaddr, uint64_t size, uint8_t* buf) {
141	        return Read(vaddr, size, buf, OPT_READ_ALL);
142	    }
143	    static bool Read(uint64_t vaddr, uint64_t size, uint8_t* buf, int opt);
144	
145	    // default non-quick search load
146	    static void ForeachLoadBlock(std::function<bool (LoadBlock *)> callback) {
147	        return ForeachLoadBlock(callback, true /** filter invalid */);
148	    }
149	    static void ForeachLoadBlock(std::function<bool (LoadBlock *)> callback, bool check) {
150	        return ForeachLoadBlock(callback, check, false /** mLoad */);
151	    }
152	    static void ForeachLoadBlock(std::function<bool (LoadBlock *)> callback, bool check, bool quick);
153	
154	    // default quick search load
155	    static inline LoadBlock* FindLoadBlock(uint64_t vaddr) {
156	        return FindLoadBlock(vaddr, true /** throw invalid */);
157	    }
158	    static inline LoadBlock* FindLoadBlock(uint64_t vaddr, bool check) {
159	        return FindLoadBlock(vaddr, check, true /** mQuickLoad */);
160	    }
161	    static inline LoadBlock* FindLoadBlock(uint64_t vaddr, bool check, bool quick) {
162	        LoadBlock* block = INSTANCE->findLoadBlock(vaddr, quick);
163	        if (check) {
164	            if (block && block->isValid())
165	                return block;
166	            throw InvalidAddressException(vaddr);
167	        }
168	        return block;
169	    }
170	    static uint64_t DlSym(const char* symbol);
171	    static uint64_t DlSym(const char* path, const char* symbol);
172	    static void ForeachThread(std::function<bool (ThreadApi *)> callback);
173	    static uint64_t NewLoadBlock(uint64_t size) {
174	        return NewLoadBlock(0x0, size);
175	    }
176	    static uint64_t NewLoadBlock(uint64_t vaddr, uint64_t size) {
177	        return NewLoadBlock(vaddr, size, Block::FLAG_R | Block::FLAG_W);
178	    }
179	    static uint64_t NewLoadBlock(uint64_t vaddr, uint64_t size, int flags);
180	    static void RegisterSysRootListener(std::function<void (LinkMap *)> fn) {
181	        SYSROOT_CALLBACK = fn;
182	    }
183	
184	    CoreApi(std::unique_ptr<MemoryMap>& map)
185	            : pointer_mask(-1),
186	              vabits_mask(-1),
187	              page_size(0) {
188	        mCore = std::move(map);
189	    }
190	    virtual ~CoreApi();
191	    uint64_t begin();
192	    uint64_t size();
193	    std::string& getName();
194	    void addLoadBlock(std::shared_ptr<LoadBlock>& block);
195	
196	    /*
197	     * strongly increasing sort
198	     * M0 S1   E1M1 S2M2 E2M3...
199	     *  | *----*  | *-|--* | ...
200	     *  M0 S1 < E1 <= M1 < S2 <= M2 < E2 <= M3 ...
201	     */
202	    inline LoadBlock* findLoadBlock(uint64_t vaddr, bool quick) {
203	        std::vector<std::shared_ptr<LoadBlock>>& loads = getLoads(quick);
204	        if (loads.empty()) return nullptr;
205	
206	        int left = 0;
207	        int right = loads.size();
208	        uint64_t clocaddr = vaddr & vabits_mask;
209	
210	        if (clocaddr < loads[left]->vaddr()
211	                || clocaddr >= (loads[right - 1]->vaddr() + loads[right - 1]->memsz()))
212	           return nullptr;
213	
214	        while (left < right) {
215	            int mid = left + (right - left) / 2;
216	            LoadBlock* block = loads[mid].get();
217	            if (block->vaddr() > clocaddr) {
218	                right = mid;
219	            } else {
220	                if (clocaddr < (block->vaddr() + block->memsz()))
221	                    return block;
222	                left = mid + 1;
223	            }
224	        }
225	        return nullptr;
226	    }
227	    void removeAllLoadBlock();
228	    void removeAllBindMap();
229	    inline uint64_t v2r(uint64_t vaddr, int opt);
230	    inline uint64_t r2v(uint64_t raddr);
231	    inline bool virtualValid(uint64_t vaddr);
232	    void addNoteBlock(std::unique_ptr<NoteBlock>& block);
233	    void removeAllNoteBlock();
234	    uint64_t findAuxv(uint64_t type);
235	    ThreadApi* findThread(int tid);
236	    void addLinkMap(uint64_t map);
237	    void removeAllLinkMap();
238	    void foreachThread(std::function<bool (ThreadApi *)> callback);
239	    void foreachFile(std::function<bool (File *)> callback);
240	    void foreachAuxv(std::function<bool (Auxv *)> callback);
241	    void foreachLinkMap(std::function<bool (LinkMap *)> callback);
242	    void foreachLoadBlock(std::function<bool (LoadBlock *)> callback, bool check, bool quick);
243	    uint64_t newLoadBlock(uint64_t vaddr, uint64_t size, int flags);
244	    uint64_t getPageSize();
245	    inline std::vector<std::shared_ptr<LoadBlock>>& getLoads(bool quick) {
246	        return quick? mQuickLoad : mLoad;
247	    }
248	    inline std::vector<std::unique_ptr<NoteBlock>>& getNotes() {
249	        return mNote;
250	    }
251	    bool isRemote() { return mRemote; }
252	    static bool QUICK_LOAD_ENABLED;
253	    static uint64_t VA_BITS;
254	protected:
255	    uint64_t pointer_mask;
256	    uint64_t vabits_mask;
257	    uint64_t page_size;
258	private:
259	    static std::unique_ptr<CoreApi> INSTANCE;
260	    virtual bool load() = 0;
261	    virtual void unload() = 0;
262	    virtual const char* getMachineName() = 0;
263	    virtual int bits() = 0;
264	    virtual int getMachine() = 0;
265	    virtual int getPointSize() = 0;
266	    virtual void loadLinkMap() = 0;
267	    virtual bool exec(uint64_t phdr, const char* file) = 0;
268	    virtual bool sysroot(LinkMap* handle, const char* file, const char* subfile) = 0;
269	    virtual api::MemoryRef& r_debug_ptr() = 0;
270	
271	    std::unique_ptr<MemoryMap> mCore;
272	    std::vector<std::shared_ptr<LoadBlock>> mLoad;
273	    std::vector<std::shared_ptr<LoadBlock>> mQuickLoad;
274	    std::vector<std::unique_ptr<NoteBlock>> mNote;
275	    std::vector<std::unique_ptr<LinkMap>> mLinkMap;
276	    static std::function<void (LinkMap *)> SYSROOT_CALLBACK;
277	    bool mRemote = false;
278	};
279	
280	#endif // CORE_API_CORE_H_
