59	bool CoreApi::Load(std::unique_ptr<MemoryMap>& map, bool remote, std::function<void ()> callback) {
60	    if (map) {
61	        ElfHeader* header = reinterpret_cast<ElfHeader*>(map->data());
62	        if (memcmp(header->ident, ELFMAG, 4)) {
63	            LOGE("Invalid ELF file.\n");
64	            return false;
65	        }
66	
67	        if (header->type != ET_CORE) {
68	            LOGE("Invalid Core file.\n");
69	            return false;
70	        }
71	
72	        switch(header->machine) {
73	#if defined(__LP64__)
74	            case EM_AARCH64:
75	                INSTANCE = std::make_unique<arm64::Core>(map);
76	                break;
77	            case EM_RISCV:
78	                INSTANCE = std::make_unique<riscv64::Core>(map);
79	                break;
80	            case EM_X86_64:
81	                INSTANCE = std::make_unique<x86_64::Core>(map);
82	                break;
83	#endif // __LP64__
84	            case EM_ARM:
85	                INSTANCE = std::make_unique<arm::Core>(map);
86	                break;
87	            case EM_386:
88	                INSTANCE = std::make_unique<x86::Core>(map);
89	                break;
90	            default:
91	                LOGW("Not support machine (%s)\n", ElfHeader::ToMachineName(header->machine).c_str());
92	                break;
93	        }
94	
95	        if (INSTANCE) {
96	            CoreApi::Init();
97	            INSTANCE->mRemote = remote;
98	            if (INSTANCE->load()) {
99	                auto bind_file = [&](File* file) -> bool {
100	                    LoadBlock* block = INSTANCE->findLoadBlock(file->begin(), false);
101	                    if (block && block->vaddr() == file->begin())
102	                        block->setFile(file->name(), file->offset());
103	                    return false;
104	                };
105	                INSTANCE->foreachFile(bind_file);
106	                if (callback) callback();
107	                return true;
108	            }
109	            return false;
110	        }
111	    }
112	    return false;
113	}
