163	uint64_t CoreApi::newLoadBlock(uint64_t vaddr, uint64_t old_size, int flags) {
164	    int idxInLoad = 0;
165	    int idxInQuick = 0;
166	
167	    uint64_t begin = RoundUp(vaddr & vabits_mask, ELF_PAGE_SIZE);
168	    uint64_t size = RoundUp(old_size, ELF_PAGE_SIZE);
169	
170	    if (!size) {
171	        LOGE("Can not fake malloc size 0x%" PRIx64 "\n", size);
172	        return 0;
173	    }
174	
175	    if (mLoad.empty()) {
176	        if (!begin) begin = FAKE_LOAD_BEGIN;
177	        if ((begin + size) > vabits_mask) {
178	            LOGE("Can not fake malloc size 0x%" PRIx64 "\n", size);
179	            return 0;
180	        }
181	    } else {
182	        LoadBlock* block = findLoadBlock(begin, false);
183	        if (block) {
184	            LOGE("Can not fake malloc vaddr 0x%" PRIx64 "\n", begin);
185	            return 0;
186	        }
187	
188	        if (begin) {
189	            for (; idxInLoad < mLoad.size(); ++idxInLoad) {
190	                if (mLoad[idxInLoad]->vaddr() > begin || idxInLoad == mLoad.size() - 1) {
191	                    uint64_t endaddr = mLoad[idxInLoad]->vaddr();
192	                    if (idxInLoad == mLoad.size() - 1)
193	                        endaddr = vabits_mask;
194	                    if ((begin + size) > endaddr) {
195	                        LOGE("Can not fake malloc vaddr 0x%" PRIx64 ", size(0x%" PRIx64 ") bigger.\n", begin, size);
196	                        return 0;
197	                    }
198	                    break;
199	                }
200	            }
201	
202	            for (; idxInQuick < mQuickLoad.size(); ++idxInQuick) {
203	                if (mQuickLoad[idxInQuick]->vaddr() > begin)
204	                    break;
205	            }
206	        } else {
207	            std::shared_ptr<LoadBlock> left = mLoad[0];
208	            if (FAKE_LOAD_BEGIN + size <= left->vaddr()) {
209	                begin = FAKE_LOAD_BEGIN;
210	            } else {
211	                for (int idx = 1; idx < mLoad.size(); ++idx) {
212	                    std::shared_ptr<LoadBlock> right = mLoad[idx];
213	                    if (right->vaddr() - (left->vaddr() + left->memsz()) >= size) {
214	                        idxInLoad = idx;
215	                        begin = left->vaddr() + left->memsz();
216	                        break;
217	                    } else {
218	                        left = right;
219	                    }
220	                }
221	                if (!begin) {
222	                    LOGE("Can not fake malloc size 0x%" PRIx64 "\n", size);
223	                    return 0x0;
224	                }
225	
226	                for (; idxInQuick < mQuickLoad.size(); ++idxInQuick) {
227	                    if (mQuickLoad[idxInQuick]->vaddr() > begin)
228	                        break;
229	                }
230	            }
231	        }
232	    }
233	
234	    std::shared_ptr<LoadBlock> block(new LoadBlock(flags,    // flags
235	                                                   0x0,      // offset
236	                                                   begin,    // vaddr
237	                                                   0x0,      // paddr
238	                                                   0x0,      // filesz
239	                                                   size,     // memsz
240	                                                   0x1000)); // align
241	    block->setTruncated(false);
242	    block->setFake(true);
243	    block->setVabitsMask(CoreApi::GetVabitsMask());
244	    block->setPointMask(CoreApi::GetPointMask());
245	
246	    if (!block->newOverlay())
247	        return 0x0;
248	
249	    mLoad.insert(mLoad.begin() + idxInLoad, block);
250	    if (!QUICK_LOAD_ENABLED || block->flags())
251	        mQuickLoad.insert(mQuickLoad.begin() + idxInQuick, block);
252	    return begin;
253	}
