339	LinkMap* CoreApi::FindLinkMap(const char* path) {
340	    LinkMap* handle = nullptr;
341	    LinkMap* second = nullptr;
342	    std::filesystem::path file(path);
343	    auto callback = [&](LinkMap* map) -> bool {
344	        if (!strcmp(map->name(), path))
345	            handle = map;
346	
347	        if (strstr(map->name(), file.filename().string().c_str()))
348	            second = map;
349	
350	        LoadBlock* block = map->block();
351	        if (block && block->isMmapBlock()) {
352	            std::size_t index = block->name().find(path);
353	            if (index != std::string::npos) {
354	                std::filesystem::path outer(block->name());
355	                if (file.filename() == outer.filename())
356	                    handle = map;
357	            }
358	
359	            index = block->name().find(file.filename().string());
360	            if (index != std::string::npos) {
361	                std::filesystem::path outer(block->name());
362	                if (file.filename() == outer.filename())
363	                    second = map;
364	            }
365	        }
366	        return handle ? true : false;
367	    };
368	    INSTANCE->foreachLinkMap(callback);
369	    return handle ? handle : second;
370	}
