380	void CoreApi::ExecFile(const char* path) {
381	    std::vector<char *> dirs;
382	    std::unique_ptr<char[], void(*)(void*)> newpath(strdup(path), free);
383	    char *token = strtok(newpath.get(), ":");
384	    while (token != nullptr) {
385	        dirs.push_back(token);
386	        token = strtok(nullptr, ":");
387	    }
388	
389	    uint64_t phdr = FindAuxv(AT_PHDR);
390	    api::MemoryRef execfn = FindAuxv(AT_EXECFN);
391	    if (execfn.IsValid()) {
392	        std::string filepath;
393	        const char* search = reinterpret_cast<const char*>(execfn.Real());
394	        for (char *dir : dirs) {
395	            if (Utils::SearchFile(dir, &filepath, search))
396	                break;
397	        }
398	        if (filepath.length() > 0) {
399	            INSTANCE->exec(phdr, filepath.c_str());
400	        }
401	    }
402	}
