533	ThreadApi* CoreApi::findThread(int tid) {
534	    for (const auto& block : mNote) {
535	        for (const auto& thread : block->getThread()) {
536	            if (thread->pid() == tid)
537	                return thread.get();
538	        }
539	    }
540	    return nullptr;
541	}
