91	// ULEB128 / SLEB128
92	uint64_t DwarfLoader::ReadULEB128(const uint8_t** ptr, const uint8_t* end) {
93	    uint64_t result = 0;
94	    int shift = 0;
95	    while (*ptr < end && shift < 64) {
96	        uint8_t b = **ptr;
97	        (*ptr)++;
98	        result |= (uint64_t)(b & 0x7f) << shift;
99	        shift += 7;
100	        if (!(b & 0x80)) break;
101	    }
102	    return result;
103	}
104	
105	int64_t DwarfLoader::ReadSLEB128(const uint8_t** ptr, const uint8_t* end) {
106	    int64_t result = 0;
107	    int shift = 0;
108	    uint8_t b = 0;
109	    while (*ptr < end && shift < 64) {
110	        b = **ptr;
111	        (*ptr)++;
112	        result |= (int64_t)(b & 0x7f) << shift;
113	        shift += 7;
114	        if (!(b & 0x80)) break;
115	    }
116	    if (shift < 64 && (b & 0x40))
117	        result |= -(int64_t)(1LL << shift);
118	    return result;
119	}
