121	// Returns true for CU-relative reference forms.
122	static bool IsRelRef(uint32_t form) {
123	    return form == DW_FORM_ref1 || form == DW_FORM_ref2 || form == DW_FORM_ref4 ||
124	           form == DW_FORM_ref8 || form == DW_FORM_ref_udata;
125	}
