127	// debug_str lookup
128	const char* DwarfLoader::GetDebugStr(uint64_t offset) const {
129	    if (!debug_str_data_ || offset >= debug_str_size_)
130	        return nullptr;
131	    // ensure null-terminated within bounds
132	    const char* s = reinterpret_cast<const char*>(debug_str_data_ + offset);
133	    const char* end = reinterpret_cast<const char*>(debug_str_data_ + debug_str_size_);
134	    const char* p = s;
135	    while (p < end && *p) ++p;
136	    if (p >= end) return nullptr;
137	    return s;
138	}
