140	// DWARF 5: DW_FORM_strx* → index into .debug_str_offsets[str_offsets_base + index*N]
141	//          → offset into .debug_str
142	const char* DwarfLoader::GetDebugStrX(uint64_t index, uint64_t str_offsets_base,
143	                                       bool dwarf64) const {
144	    if (!debug_str_offsets_data_) return nullptr;
145	    uint64_t entry_size = dwarf64 ? 8 : 4;
146	    uint64_t off = str_offsets_base + index * entry_size;
147	    if (off + entry_size > debug_str_offsets_size_) return nullptr;
148	    const uint8_t* p = debug_str_offsets_data_ + off;
149	    uint64_t str_off;
150	    if (dwarf64) {
151	        str_off = (uint64_t)p[0] | ((uint64_t)p[1] << 8) | ((uint64_t)p[2] << 16)
152	                | ((uint64_t)p[3] << 24) | ((uint64_t)p[4] << 32) | ((uint64_t)p[5] << 40)
153	                | ((uint64_t)p[6] << 48) | ((uint64_t)p[7] << 56);
154	    } else {
155	        str_off = (uint32_t)p[0] | ((uint32_t)p[1] << 8)
156	                | ((uint32_t)p[2] << 16) | ((uint32_t)p[3] << 24);
157	    }
158	    return GetDebugStr(str_off);
159	}
