161	// ParseExprloc
162	bool DwarfLoader::ParseExprloc(const uint8_t* data, uint64_t size, uint64_t* out_value) {
163	    if (!data || size == 0) return false;
164	    const uint8_t* end = data + size;
165	    if (data[0] == DW_OP_plus_uconst) {
166	        const uint8_t* p = data + 1;
167	        if (p >= end) return false;
168	        *out_value = ReadULEB128(&p, end);
169	        return true;
170	    }
171	    // DW_OP_constu (0x10) + value — also common
172	    if (data[0] == 0x10) {
173	        const uint8_t* p = data + 1;
174	        if (p >= end) return false;
175	        *out_value = ReadULEB128(&p, end);
176	        return true;
177	    }
178	    return false;
179	}
