181	// Advances *ptr past the attribute value. Writes to out_value / out_str if
182	// non-null and the form provides the respective type.
183	// Returns updated ptr, or nullptr on fatal parse error.
184	const uint8_t* DwarfLoader::ReadAttrValue(const uint8_t* ptr, const uint8_t* end,
185	                                           uint32_t form, uint32_t addr_size,
186	                                           bool dwarf64, uint64_t str_offsets_base,
187	                                           uint64_t* out_value, std::string* out_str) {
188	    if (!ptr || ptr >= end) return nullptr;
189	
190	    auto read_u8  = [&]() -> uint8_t  { uint8_t  v = *ptr; ptr += 1; return v; };
191	    auto read_u16 = [&]() -> uint16_t {
192	        uint16_t v = (uint16_t)ptr[0] | ((uint16_t)ptr[1] << 8);
193	        ptr += 2; return v;
194	    };
195	    auto read_u32 = [&]() -> uint32_t {
196	        uint32_t v = (uint32_t)ptr[0] | ((uint32_t)ptr[1] << 8)
197	                   | ((uint32_t)ptr[2] << 16) | ((uint32_t)ptr[3] << 24);
198	        ptr += 4; return v;
199	    };
200	    auto read_u64 = [&]() -> uint64_t {
201	        uint64_t v = 0;
202	        for (int i = 0; i < 8; ++i) v |= (uint64_t)ptr[i] << (8 * i);
203	        ptr += 8; return v;
204	    };
205	    // offset size depends on DWARF 32/64-bit encoding
206	    auto read_offset = [&]() -> uint64_t {
207	        return dwarf64 ? read_u64() : read_u32();
208	    };
209	
210	    switch (form) {
211	    case DW_FORM_addr:
212	        if (ptr + addr_size > end) return nullptr;
213	        if (out_value) {
214	            uint64_t v = 0;
215	            for (uint32_t i = 0; i < addr_size; ++i) v |= (uint64_t)ptr[i] << (8 * i);
216	            *out_value = v;
217	        }
218	        ptr += addr_size;
219	        break;
220	
221	    case DW_FORM_data1:
222	        if (ptr + 1 > end) return nullptr;
223	        if (out_value) *out_value = read_u8(); else ptr += 1;
224	        break;
225	
226	    case DW_FORM_data2:
227	        if (ptr + 2 > end) return nullptr;
228	        if (out_value) *out_value = read_u16(); else ptr += 2;
229	        break;
230	
231	    case DW_FORM_data4:
232	        if (ptr + 4 > end) return nullptr;
233	        if (out_value) *out_value = read_u32(); else ptr += 4;
234	        break;
235	
236	    case DW_FORM_data8:
237	        if (ptr + 8 > end) return nullptr;
238	        if (out_value) *out_value = read_u64(); else ptr += 8;
239	        break;
240	
241	    case DW_FORM_data16:
242	        if (ptr + 16 > end) return nullptr;
243	        ptr += 16;
244	        break;
245	
246	    case DW_FORM_udata:
247	    case DW_FORM_ref_udata: {
248	        uint64_t v = ReadULEB128(&ptr, end);
249	        if (out_value) *out_value = v;
250	        break;
251	    }
252	
253	    case DW_FORM_loclistx:
254	    case DW_FORM_rnglistx:
255	        ReadULEB128(&ptr, end); // skip index, not needed
256	        break;
257	
258	    case DW_FORM_addrx: {
259	        ReadULEB128(&ptr, end); // skip address index
260	        break;
261	    }
262	
263	    case DW_FORM_strx: {
264	        uint64_t idx = ReadULEB128(&ptr, end);
265	        if (out_str) {
266	            const char* s = GetDebugStrX(idx, str_offsets_base, dwarf64);
267	            if (s) *out_str = s;
268	        }
269	        break;
270	    }
271	
272	    case DW_FORM_addrx1:
273	        if (ptr + 1 > end) return nullptr;
274	        ptr += 1;
275	        break;
276	    case DW_FORM_addrx2:
277	        if (ptr + 2 > end) return nullptr;
278	        ptr += 2;
279	        break;
280	    case DW_FORM_addrx3:
281	        if (ptr + 3 > end) return nullptr;
282	        ptr += 3;
283	        break;
284	    case DW_FORM_addrx4:
285	        if (ptr + 4 > end) return nullptr;
286	        ptr += 4;
287	        break;
288	
289	    case DW_FORM_strx1: {
290	        if (ptr + 1 > end) return nullptr;
291	        uint64_t idx = *ptr++;
292	        if (out_str) {
293	            const char* s = GetDebugStrX(idx, str_offsets_base, dwarf64);
294	            if (s) *out_str = s;
295	        }
296	        break;
297	    }
298	    case DW_FORM_strx2: {
299	        if (ptr + 2 > end) return nullptr;
300	        uint64_t idx = (uint16_t)ptr[0] | ((uint16_t)ptr[1] << 8);
301	        ptr += 2;
302	        if (out_str) {
303	            const char* s = GetDebugStrX(idx, str_offsets_base, dwarf64);
304	            if (s) *out_str = s;
305	        }
306	        break;
307	    }
308	    case DW_FORM_strx3: {
309	        if (ptr + 3 > end) return nullptr;
310	        uint64_t idx = (uint32_t)ptr[0] | ((uint32_t)ptr[1] << 8) | ((uint32_t)ptr[2] << 16);
311	        ptr += 3;
312	        if (out_str) {
313	            const char* s = GetDebugStrX(idx, str_offsets_base, dwarf64);
314	            if (s) *out_str = s;
315	        }
316	        break;
317	    }
318	    case DW_FORM_strx4: {
319	        if (ptr + 4 > end) return nullptr;
320	        uint64_t idx = (uint32_t)ptr[0] | ((uint32_t)ptr[1] << 8)
321	                     | ((uint32_t)ptr[2] << 16) | ((uint32_t)ptr[3] << 24);
322	        ptr += 4;
323	        if (out_str) {
324	            const char* s = GetDebugStrX(idx, str_offsets_base, dwarf64);
325	            if (s) *out_str = s;
326	        }
327	        break;
328	    }
329	
330	    case DW_FORM_sdata: {
331	        int64_t v = ReadSLEB128(&ptr, end);
332	        if (out_value) *out_value = (uint64_t)v;
333	        break;
334	    }
335	
336	    case DW_FORM_string: {
337	        const char* s = reinterpret_cast<const char*>(ptr);
338	        while (ptr < end && *ptr) ++ptr;
339	        if (ptr >= end) return nullptr;
340	        if (out_str) *out_str = s;
341	        ++ptr; // skip null terminator
342	        break;
343	    }
344	
345	    case DW_FORM_strp:
346	    case DW_FORM_strp_sup:
347	    case DW_FORM_line_strp: {
348	        if (ptr + (dwarf64 ? 8 : 4) > end) return nullptr;
349	        uint64_t off = read_offset();
350	        if (form == DW_FORM_strp && out_str) {
351	            const char* s = GetDebugStr(off);
352	            if (s) *out_str = s;
353	        }
354	        break;
355	    }
356	
357	    case DW_FORM_block1: {
358	        if (ptr + 1 > end) return nullptr;
359	        uint64_t len = read_u8();
360	        if (ptr + len > end) return nullptr;
361	        if (out_value) ParseExprloc(ptr, len, out_value);
362	        ptr += len;
363	        break;
364	    }
365	
366	    case DW_FORM_block2: {
367	        if (ptr + 2 > end) return nullptr;
368	        uint64_t len = read_u16();
369	        if (ptr + len > end) return nullptr;
370	        if (out_value) ParseExprloc(ptr, len, out_value);
371	        ptr += len;
372	        break;
373	    }
374	
375	    case DW_FORM_block4: {
376	        if (ptr + 4 > end) return nullptr;
377	        uint64_t len = read_u32();
378	        if (ptr + len > end) return nullptr;
379	        if (out_value) ParseExprloc(ptr, len, out_value);
380	        ptr += len;
381	        break;
382	    }
383	
384	    case DW_FORM_block:
385	    case DW_FORM_exprloc: {
386	        uint64_t len = ReadULEB128(&ptr, end);
387	        if (ptr + len > end) return nullptr;
388	        if (out_value) ParseExprloc(ptr, len, out_value);
389	        ptr += len;
390	        break;
391	    }
392	
393	    case DW_FORM_flag:
394	        if (ptr + 1 > end) return nullptr;
395	        if (out_value) *out_value = read_u8(); else ptr += 1;
396	        break;
397	
398	    case DW_FORM_flag_present:
399	        // zero bytes
400	        if (out_value) *out_value = 1;
401	        break;
402	
403	    case DW_FORM_ref1:
404	        if (ptr + 1 > end) return nullptr;
405	        if (out_value) *out_value = read_u8(); else ptr += 1;
406	        break;
407	
408	    case DW_FORM_ref2:
409	        if (ptr + 2 > end) return nullptr;
410	        if (out_value) *out_value = read_u16(); else ptr += 2;
411	        break;
412	
413	    case DW_FORM_ref4:
414	    case DW_FORM_ref_sup4:
415	        if (ptr + 4 > end) return nullptr;
416	        if (out_value) *out_value = read_u32(); else ptr += 4;
417	        break;
418	
419	    case DW_FORM_ref8:
420	    case DW_FORM_ref_sup8:
421	    case DW_FORM_ref_sig8:
422	        if (ptr + 8 > end) return nullptr;
423	        if (out_value) *out_value = read_u64(); else ptr += 8;
424	        break;
425	
426	    case DW_FORM_ref_addr:
427	    case DW_FORM_sec_offset:
428	        if (ptr + (dwarf64 ? 8 : 4) > end) return nullptr;
429	        if (out_value) *out_value = read_offset(); else ptr += (dwarf64 ? 8 : 4);
430	        break;
431	
432	    case DW_FORM_indirect: {
433	        uint32_t real_form = (uint32_t)ReadULEB128(&ptr, end);
434	        return ReadAttrValue(ptr, end, real_form, addr_size, dwarf64,
435	                             str_offsets_base, out_value, out_str);
436	    }
437	
438	    case DW_FORM_implicit_const:
439	        // value was stored in abbrev entry, nothing in .debug_info
440	        break;
441	
442	    default:
443	        // Unknown form — we cannot advance safely.
444	        // Return nullptr to signal parse error to the caller.
445	        LOGD("unknown form 0x%x, stopping CU parse\n", form);
446	        return nullptr;
447	    }
448	
449	    return ptr;
450	}
