452	const uint8_t* DwarfLoader::ParseAbbrevTable(const uint8_t* ptr, const uint8_t* end,
453	                                              uint64_t base_offset) {
454	    AbbrevTable table;
455	
456	    while (ptr < end) {
457	        uint64_t code = ReadULEB128(&ptr, end);
458	        if (code == 0) break; // end of table
459	
460	        AbbrevEntry entry;
461	        entry.code = (uint32_t)code;
462	        entry.tag  = (uint32_t)ReadULEB128(&ptr, end);
463	
464	        if (ptr >= end) break;
465	        entry.has_children = (*ptr++ == DW_CHILDREN_yes);
466	
467	        // Read attribute specs
468	        while (ptr < end) {
469	            uint32_t attr_name = (uint32_t)ReadULEB128(&ptr, end);
470	            uint32_t attr_form = (uint32_t)ReadULEB128(&ptr, end);
471	            if (attr_name == 0 && attr_form == 0) break;
472	
473	            AttrSpec spec;
474	            spec.name = attr_name;
475	            spec.form = attr_form;
476	            spec.implicit_const = 0;
477	
478	            if (attr_form == DW_FORM_implicit_const) {
479	                // DWARF 5: the value follows as SLEB128 in the abbrev table
480	                spec.implicit_const = ReadSLEB128(&ptr, end);
481	            }
482	
483	            entry.attrs.push_back(spec);
484	        }
485	
486	        table[entry.code] = entry;
487	    }
488	
489	    abbrev_map_[base_offset] = std::move(table);
490	    return ptr;
491	}
492	
493	void DwarfLoader::ParseAbbrevSection() {
494	    if (!debug_abbrev_data_) return;
495	
496	    const uint8_t* ptr = debug_abbrev_data_;
497	    const uint8_t* end = debug_abbrev_data_ + debug_abbrev_size_;
498	
499	    while (ptr < end) {
500	        uint64_t offset = (uint64_t)(ptr - debug_abbrev_data_);
501	        const uint8_t* next = ParseAbbrevTable(ptr, end, offset);
502	        if (!next || next <= ptr) break;
503	        ptr = next;
504	    }
505	    LOGD("abbrev_size=%lu  tables=%zu\n",
506	         (unsigned long)debug_abbrev_size_, abbrev_map_.size());
507	}
508	
509	const uint8_t* DwarfLoader::ParseDIETree(const uint8_t* ptr, const uint8_t* cu_end,
510	                                          uint32_t addr_size, bool dwarf64,
511	                                          const AbbrevTable& abbrev_table,
512	                                          const std::string& ns_prefix,
513	                                          uint64_t str_offsets_base,
514	                                          uint64_t cu_base_offset) {
515	    // Use index instead of pointer to avoid dangling refs after structs_ reallocation.
516	    static constexpr int kNoStruct = -1;
517	
518	    struct StackFrame {
519	        std::string ns_prefix;
520	        int struct_idx; // index into structs_, or kNoStruct
521	    };
522	
523	    std::stack<StackFrame> stk;
524	    std::string cur_ns = ns_prefix;
525	    int cur_struct_idx = kNoStruct;
526	
527	    while (ptr < cu_end) {
528	        uint64_t die_abs_offset = (uint64_t)(ptr - debug_info_data_);
529	        uint64_t code = ReadULEB128(&ptr, cu_end);
530	
531	        if (code == 0) {
532	            // Null DIE: pop scope
533	            if (stk.empty()) break;
534	            cur_ns         = stk.top().ns_prefix;
535	            cur_struct_idx = stk.top().struct_idx;
536	            stk.pop();
537	            continue;
538	        }
539	
540	        auto it = abbrev_table.find((uint32_t)code);
541	        if (it == abbrev_table.end()) {
542	            // Corrupted or unknown abbrev code — stop parsing this CU
543	            LOGD("unknown abbrev code %lu, stopping CU parse\n", (unsigned long)code);
544	            return nullptr;
545	        }
546	
547	        const AbbrevEntry& entry = it->second;
548	
549	        // Read all attributes
550	        std::string die_name;
551	        uint64_t member_loc  = 0;  bool has_member_loc = false;
552	        uint64_t byte_sz     = 0;  bool has_byte_sz    = false;
553	        uint64_t type_ref    = 0;  uint32_t type_ref_form = 0;
554	
555	        for (const AttrSpec& attr : entry.attrs) {
556	            uint64_t v = 0;
557	            std::string s;
558	
559	            if (attr.form == DW_FORM_implicit_const) {
560	                v = (uint64_t)attr.implicit_const;
561	                // no bytes consumed from .debug_info
562	            } else {
563	                const uint8_t* next = ReadAttrValue(ptr, cu_end, attr.form,
564	                                                     addr_size, dwarf64,
565	                                                     str_offsets_base, &v, &s);
566	                if (!next) {
567	                    // parse error; skip to end of CU
568	                    return nullptr;
569	                }
570	                ptr = next;
571	            }
572	
573	            switch (attr.name) {
574	            case DW_AT_name:
575	                if (!s.empty()) die_name = s;
576	                break;
577	            case DW_AT_data_member_location:
578	                member_loc = v;
579	                has_member_loc = true;
580	                break;
581	            case DW_AT_byte_size:
582	                byte_sz = v;
583	                has_byte_sz = true;
584	                break;
585	            case DW_AT_type:
586	                type_ref = v;
587	                type_ref_form = attr.form;
588	                break;
589	            default:
590	                break;
591	            }
592	        }
593	
594	        // Convert CU-relative type ref to absolute .debug_info offset
595	        uint64_t abs_type_ref = type_ref_form ?
596	            (IsRelRef(type_ref_form) ? cu_base_offset + type_ref : type_ref) : 0;
597	
598	        // Handle DIE by tag
599	        switch (entry.tag) {
600	        case DW_TAG_namespace: {
601	            if (entry.has_children) {
602	                std::string new_ns = cur_ns.empty() ? die_name
603	                                                    : (cur_ns + "::" + die_name);
604	                stk.push({cur_ns, cur_struct_idx});
605	                cur_ns = new_ns;
606	                // cur_struct_idx unchanged — namespace doesn't reset struct context
607	            }
608	            break;
609	        }
610	
611	        case DW_TAG_structure_type:
612	        case DW_TAG_class_type: {
613	            if (!die_name.empty()) {
614	                std::string full_name = cur_ns.empty() ? die_name
615	                                                       : (cur_ns + "::" + die_name);
616	                // Register in type registry so members/bases can reference this type
617	                type_registry_[die_abs_offset] = {full_name, 0, 0};
618	                // push_back may reallocate; record index before, set after
619	                structs_.push_back({full_name, (uint32_t)byte_sz, has_byte_sz, {}, {}});
620	                int new_idx = (int)structs_.size() - 1;
621	                if (entry.has_children) {
622	                    stk.push({cur_ns, cur_struct_idx});
623	                    cur_struct_idx = new_idx;
624	                }
625	            } else {
626	                // anonymous struct/class
627	                if (entry.has_children) {
628	                    stk.push({cur_ns, cur_struct_idx});
629	                    cur_struct_idx = kNoStruct;
630	                }
631	            }
632	            break;
633	        }
634	
635	        case DW_TAG_member: {
636	            if (cur_struct_idx != kNoStruct && !die_name.empty()) {
637	                structs_[cur_struct_idx].members.push_back(
638	                    {die_name, "", (uint32_t)member_loc, has_member_loc});
639	                if (abs_type_ref) {
640	                    int member_idx = (int)structs_[cur_struct_idx].members.size() - 1;
641	                    pending_refs_.push_back({cur_struct_idx, false, member_idx, abs_type_ref});
642	                }
643	            }
644	            if (entry.has_children) {
645	                stk.push({cur_ns, cur_struct_idx});
646	                cur_struct_idx = kNoStruct;
647	            }
648	            break;
649	        }
650	
651	        case DW_TAG_inheritance: {
652	            if (cur_struct_idx != kNoStruct) {
653	                structs_[cur_struct_idx].bases.push_back(
654	                    {"", (uint32_t)member_loc, has_member_loc});
655	                if (abs_type_ref) {
656	                    int base_idx = (int)structs_[cur_struct_idx].bases.size() - 1;
657	                    pending_refs_.push_back({cur_struct_idx, true, base_idx, abs_type_ref});
658	                }
659	            }
660	            if (entry.has_children) {
661	                stk.push({cur_ns, cur_struct_idx});
662	                cur_struct_idx = kNoStruct;
663	            }
664	            break;
665	        }
666	
667	        case DW_TAG_base_type:
668	        case DW_TAG_enumeration_type:
669	        case DW_TAG_union_type: {
670	            if (!die_name.empty()) {
671	                std::string full_name = cur_ns.empty() ? die_name
672	                                                       : (cur_ns + "::" + die_name);
673	                type_registry_[die_abs_offset] = {full_name, 0, 0};
674	            }
675	            if (entry.has_children) {
676	                stk.push({cur_ns, cur_struct_idx});
677	                cur_struct_idx = kNoStruct;
678	            }
679	            break;
680	        }
681	
682	        case DW_TAG_typedef: {
683	            if (!die_name.empty()) {
684	                std::string full_name = cur_ns.empty() ? die_name
685	                                                       : (cur_ns + "::" + die_name);
686	                type_registry_[die_abs_offset] = {full_name, abs_type_ref, 5};
687	            }
688	            if (entry.has_children) {
689	                stk.push({cur_ns, cur_struct_idx});
690	                cur_struct_idx = kNoStruct;
691	            }
692	            break;
693	        }
694	
695	        case DW_TAG_pointer_type:
696	        case DW_TAG_rvalue_reference_type:
697	            type_registry_[die_abs_offset] = {"", abs_type_ref, 1};
698	            if (entry.has_children) {
699	                stk.push({cur_ns, cur_struct_idx});
700	                cur_struct_idx = kNoStruct;
701	            }
702	            break;
703	
704	        case DW_TAG_reference_type:
705	            type_registry_[die_abs_offset] = {"", abs_type_ref, 2};
706	            if (entry.has_children) {
707	                stk.push({cur_ns, cur_struct_idx});
708	                cur_struct_idx = kNoStruct;
709	            }
710	            break;
711	
712	        case DW_TAG_const_type:
713	            type_registry_[die_abs_offset] = {"", abs_type_ref, 3};
714	            if (entry.has_children) {
715	                stk.push({cur_ns, cur_struct_idx});
716	                cur_struct_idx = kNoStruct;
717	            }
718	            break;
719	
720	        case DW_TAG_volatile_type:
721	            type_registry_[die_abs_offset] = {"", abs_type_ref, 4};
722	            if (entry.has_children) {
723	                stk.push({cur_ns, cur_struct_idx});
724	                cur_struct_idx = kNoStruct;
725	            }
726	            break;
727	
728	        case DW_TAG_array_type:
729	            type_registry_[die_abs_offset] = {"", abs_type_ref, 6};
730	            if (entry.has_children) {
731	                stk.push({cur_ns, cur_struct_idx});
732	                cur_struct_idx = kNoStruct;
733	            }
734	            break;
735	
736	        default: {
737	            // Other tags (subprogram, …): push to skip children scope
738	            if (entry.has_children) {
739	                stk.push({cur_ns, cur_struct_idx});
740	                cur_struct_idx = kNoStruct;
741	            }
742	            break;
743	        }
744	        }
745	    }
746	
747	    return ptr;
748	}
749	
750	const uint8_t* DwarfLoader::ParseCompileUnit(const uint8_t* ptr, const uint8_t* end) {
751	    if (ptr + 4 > end) return nullptr;
752	
753	    const uint8_t* cu_start = ptr; // CU-relative refs are relative to this
754	
755	    // unit_length
756	    uint32_t unit_length_32 = (uint32_t)ptr[0] | ((uint32_t)ptr[1] << 8)
757	                             | ((uint32_t)ptr[2] << 16) | ((uint32_t)ptr[3] << 24);
758	    ptr += 4;
759	
760	    bool dwarf64 = false;
761	    uint64_t unit_length;
762	
763	    if (unit_length_32 == 0xffffffff) {
764	        // 64-bit DWARF
765	        if (ptr + 8 > end) return nullptr;
766	        unit_length = 0;
767	        for (int i = 0; i < 8; ++i) unit_length |= (uint64_t)ptr[i] << (8 * i);
768	        ptr += 8;
769	        dwarf64 = true;
770	    } else {
771	        unit_length = unit_length_32;
772	    }
773	
774	    const uint8_t* cu_end = ptr + unit_length;
775	    if (cu_end > end) return nullptr;
776	
777	    if (ptr + 2 > cu_end) return cu_end;
778	    uint16_t version = (uint16_t)ptr[0] | ((uint16_t)ptr[1] << 8);
779	    ptr += 2;
780	
781	    uint64_t abbrev_offset;
782	    uint32_t addr_size;
783	
784	    if (version >= 5) {
785	        // DWARF 5: unit_type (1 byte) + address_size (1 byte) + abbrev_offset
786	        if (ptr + 2 > cu_end) return cu_end;
787	        uint8_t unit_type = *ptr++;
788	        addr_size = *ptr++;
789	        if (unit_type != DW_UT_compile) {
790	            // Skip non-compile units (type units, etc.)
791	            return cu_end;
792	        }
793	        if (dwarf64) {
794	            if (ptr + 8 > cu_end) return cu_end;
795	            abbrev_offset = 0;
796	            for (int i = 0; i < 8; ++i) abbrev_offset |= (uint64_t)ptr[i] << (8 * i);
797	            ptr += 8;
798	        } else {
799	            if (ptr + 4 > cu_end) return cu_end;
800	            abbrev_offset = (uint32_t)ptr[0] | ((uint32_t)ptr[1] << 8)
801	                          | ((uint32_t)ptr[2] << 16) | ((uint32_t)ptr[3] << 24);
802	            ptr += 4;
803	        }
804	    } else {
805	        // DWARF 2-4: abbrev_offset + address_size
806	        if (dwarf64) {
807	            if (ptr + 8 > cu_end) return cu_end;
808	            abbrev_offset = 0;
809	            for (int i = 0; i < 8; ++i) abbrev_offset |= (uint64_t)ptr[i] << (8 * i);
810	            ptr += 8;
811	        } else {
812	            if (ptr + 4 > cu_end) return cu_end;
813	            abbrev_offset = (uint32_t)ptr[0] | ((uint32_t)ptr[1] << 8)
814	                          | ((uint32_t)ptr[2] << 16) | ((uint32_t)ptr[3] << 24);
815	            ptr += 4;
816	        }
817	        if (ptr + 1 > cu_end) return cu_end;
818	        addr_size = *ptr++;
819	    }
820	
821	    // Print first 3 CUs only to avoid flooding output on large .so files
822	    static int cu_diag_count = 0;
823	    bool diag = (cu_diag_count++ < 3);
824	    if (diag)
825	        LOGD("CU#%d version=%u  unit_length=%lu  addr_size=%u"
826	             "  abbrev_offset=%lu  dwarf64=%d\n",
827	             cu_diag_count, version, (unsigned long)unit_length, addr_size,
828	             (unsigned long)abbrev_offset, (int)dwarf64);
829	
830	    // Locate the abbrev table for this CU
831	    auto it = abbrev_map_.find(abbrev_offset);
832	    if (it == abbrev_map_.end()) {
833	        LOGD("abbrev table not found at offset %lu\n", (unsigned long)abbrev_offset);
834	        return cu_end;
835	    }
836	
837	    // Peek at the compile_unit DIE to read DW_AT_str_offsets_base (DWARF 5).
838	    // We scan its attributes without advancing ptr, so ParseDIETree still
839	    // processes the full CU starting from the compile_unit DIE.
840	    uint64_t str_offsets_base = 0;
841	    {
842	        const uint8_t* peek = ptr;
843	        uint64_t cu_die_code = ReadULEB128(&peek, cu_end);
844	        auto cu_die_it = it->second.find((uint32_t)cu_die_code);
845	        if (cu_die_it != it->second.end()) {
846	            for (const AttrSpec& attr : cu_die_it->second.attrs) {
847	                uint64_t v = 0;
848	                if (attr.form == DW_FORM_implicit_const) {
849	                    v = (uint64_t)attr.implicit_const;
850	                } else {
851	                    const uint8_t* next = ReadAttrValue(peek, cu_end, attr.form,
852	                                                         addr_size, dwarf64, 0,
853	                                                         (attr.name == DW_AT_str_offsets_base) ? &v : nullptr,
854	                                                         nullptr);
855	                    if (!next) break;
856	                    peek = next;
857	                }
858	                if (attr.name == DW_AT_str_offsets_base) {
859	                    str_offsets_base = v;
860	                    break;
861	                }
862	            }
863	        }
864	    }
865	
866	    if (diag)
867	        LOGD("str_offsets_base=%lu  abbrev_entries=%zu\n",
868	             (unsigned long)str_offsets_base, it->second.size());
869	
870	    uint64_t cu_base_offset = (uint64_t)(cu_start - debug_info_data_);
871	    size_t structs_before = structs_.size();
872	    const uint8_t* die_end = ParseDIETree(ptr, cu_end, addr_size, dwarf64,
873	                                           it->second, "", str_offsets_base, cu_base_offset);
874	    if (diag)
875	        LOGD("structs found in this CU: %zu  (die_end=%s)\n",
876	             structs_.size() - structs_before, die_end ? "ok" : "parse_error");
877	    return cu_end;
878	}
879	
880	std::string DwarfLoader::ResolveTypeName(uint64_t offset, int depth) const {
881	    if (depth > 8 || offset == 0) return "";
882	    auto it = type_registry_.find(offset);
883	    if (it == type_registry_.end()) return "";
884	    const TypeEntry& e = it->second;
885	    switch (e.qualifier) {
886	    case 0: return e.name;                                                       // named type
887	    case 1: return ResolveTypeName(e.type_ref, depth + 1) + "*";                // pointer/rref
888	    case 2: return ResolveTypeName(e.type_ref, depth + 1) + "&";                // reference
889	    case 3: { auto s = ResolveTypeName(e.type_ref, depth + 1);                  // const
890	              return s.empty() ? "const" : "const " + s; }
891	    case 4: { auto s = ResolveTypeName(e.type_ref, depth + 1);                  // volatile
892	              return s.empty() ? "volatile" : "volatile " + s; }
893	    case 5: return !e.name.empty() ? e.name : ResolveTypeName(e.type_ref, depth + 1); // typedef
894	    case 6: return ResolveTypeName(e.type_ref, depth + 1) + "[]";               // array
895	    default: return e.name;
896	    }
897	}
898	
899	void DwarfLoader::ResolveTypes() {
900	    for (const auto& p : pending_refs_) {
901	        if (p.type_offset == 0) continue;
902	        std::string name = ResolveTypeName(p.type_offset, 0);
903	        if (name.empty()) continue;
904	        if (p.is_base)
905	            structs_[p.struct_idx].bases[p.item_idx].type_name = name;
906	        else
907	            structs_[p.struct_idx].members[p.item_idx].type_name = name;
908	    }
909	}
910	
911	void DwarfLoader::ParseInfoSection() {
912	    if (!debug_info_data_) return;
913	
914	    const uint8_t* ptr = debug_info_data_;
915	    const uint8_t* end = debug_info_data_ + debug_info_size_;
916	
917	    int cu_count = 0;
918	    while (ptr < end) {
919	        const uint8_t* next = ParseCompileUnit(ptr, end);
920	        if (!next || next <= ptr) break;
921	        ptr = next;
922	        ++cu_count;
923	    }
924	    LOGD("total CUs processed=%d  total structs=%zu\n",
925	         cu_count, structs_.size());
926	    ResolveTypes();
927	}
