929	// Handles ELF SHF_COMPRESSED sections (Elf_Chdr prefix + compressed payload).
930	// Stores decompressed data in decompressed_sections_ and points out_data/out_size
931	// at the result. Returns false if unsupported or decompression fails.
932	bool DwarfLoader::DecompressSection(const uint8_t* raw, uint64_t raw_size,
933	                                    const uint8_t** out_data, uint64_t* out_size) {
934	    // Elf64_Chdr: ch_type(4) + ch_reserved(4) + ch_size(8) + ch_addralign(8) = 24 bytes
935	    // Elf32_Chdr: ch_type(4) + ch_size(4) + ch_addralign(4)                  = 12 bytes
936	    uint64_t chdr_size = (elf_bits_ == 64) ? 24 : 12;
937	    if (raw_size < chdr_size) return false;
938	
939	    uint32_t ch_type = (uint32_t)raw[0] | ((uint32_t)raw[1] << 8)
940	                     | ((uint32_t)raw[2] << 16) | ((uint32_t)raw[3] << 24);
941	
942	    uint64_t ch_size;
943	    if (elf_bits_ == 64) {
944	        ch_size = (uint64_t)raw[8]  | ((uint64_t)raw[9]  << 8)
945	                | ((uint64_t)raw[10] << 16) | ((uint64_t)raw[11] << 24)
946	                | ((uint64_t)raw[12] << 32) | ((uint64_t)raw[13] << 40)
947	                | ((uint64_t)raw[14] << 48) | ((uint64_t)raw[15] << 56);
948	    } else {
949	        ch_size = (uint32_t)raw[4] | ((uint32_t)raw[5] << 8)
950	                | ((uint32_t)raw[6] << 16) | ((uint32_t)raw[7] << 24);
951	    }
952	
953	    const uint8_t* payload = raw + chdr_size;
954	    uint64_t payload_size  = raw_size - chdr_size;
955	
956	    if (ch_type == ELFCOMPRESS_ZSTD) {
957	#ifdef __ZSTD__
958	        decompressed_sections_.emplace_back(ch_size);
959	        auto& buf = decompressed_sections_.back();
960	        size_t result = ZSTD_decompress(buf.data(), ch_size, payload, payload_size);
961	        if (ZSTD_isError(result)) {
962	            decompressed_sections_.pop_back();
963	            LOGD("zstd decompress failed: %s\n", ZSTD_getErrorName(result));
964	            return false;
965	        }
966	        buf.resize(result);
967	        *out_data = buf.data();
968	        *out_size = result;
969	        return true;
970	#else
971	        LOGD("section is zstd-compressed but zstd support not compiled in\n");
972	        return false;
973	#endif
974	    } else if (ch_type == ELFCOMPRESS_ZLIB) {
975	        LOGD("zlib-compressed sections not supported\n");
976	        return false;
977	    }
978	
979	    LOGD("unknown compression type %u\n", ch_type);
980	    return false;
981	}
982	
983	bool DwarfLoader::LocateSections() {
984	    if (!map_) return false;
985	
986	    const uint8_t* data = reinterpret_cast<const uint8_t*>(map_->data());
987	    uint64_t size = map_->size();
988	
989	    if (size < 5 || memcmp(data, "\x7f""ELF", 4) != 0) {
990	        LOGD("not a valid ELF file\n");
991	        return false;
992	    }
993	
994	    elf_bits_ = (data[4] == 1) ? 32 : 64;
995	
996	    auto locate = [&](const char* shstr, const void* shdr_base, int sh_num,
997	                      uint64_t sh_entsize) {
998	        for (int i = 0; i < sh_num; ++i) {
999	            const uint8_t* shdr_ptr = reinterpret_cast<const uint8_t*>(shdr_base) + i * sh_entsize;
1000	            uint32_t sh_type;
1001	            uint64_t sh_offset, sh_size, sh_name_idx, sh_flags;
1002	
1003	            if (elf_bits_ == 64) {
1004	                const Elf64_Shdr* s = reinterpret_cast<const Elf64_Shdr*>(shdr_ptr);
1005	                sh_type     = s->sh_type;
1006	                sh_offset   = s->sh_offset;
1007	                sh_size     = s->sh_size;
1008	                sh_name_idx = s->sh_name;
1009	                sh_flags    = s->sh_flags;
1010	            } else {
1011	                const Elf32_Shdr* s = reinterpret_cast<const Elf32_Shdr*>(shdr_ptr);
1012	                sh_type     = s->sh_type;
1013	                sh_offset   = s->sh_offset;
1014	                sh_size     = s->sh_size;
1015	                sh_name_idx = s->sh_name;
1016	                sh_flags    = s->sh_flags;
1017	            }
1018	
1019	            if (sh_type == SHT_NOBITS) continue;
1020	            if (sh_offset + sh_size > size) continue;
1021	
1022	            // bounds-check name access
1023	            const char* name_ptr = shstr + sh_name_idx;
1024	            const uint8_t* name_addr = reinterpret_cast<const uint8_t*>(name_ptr);
1025	            if (name_addr < data || name_addr >= data + size) continue;
1026	
1027	            const char* name = name_ptr;
1028	            const uint8_t** sec_data = nullptr;
1029	            uint64_t*        sec_size = nullptr;
1030	
1031	            if      (!strcmp(name, ".debug_abbrev"))      { sec_data = &debug_abbrev_data_;      sec_size = &debug_abbrev_size_; }
1032	            else if (!strcmp(name, ".debug_info"))        { sec_data = &debug_info_data_;        sec_size = &debug_info_size_; }
1033	            else if (!strcmp(name, ".debug_str"))         { sec_data = &debug_str_data_;         sec_size = &debug_str_size_; }
1034	            else if (!strcmp(name, ".debug_str_offsets")) { sec_data = &debug_str_offsets_data_; sec_size = &debug_str_offsets_size_; }
1035	
1036	            if (!sec_data) continue;
1037	
1038	            if (sh_flags & SHF_COMPRESSED) {
1039	                DecompressSection(data + sh_offset, sh_size, sec_data, sec_size);
1040	            } else {
1041	                *sec_data = data + sh_offset;
1042	                *sec_size = sh_size;
1043	            }
1044	        }
1045	    };
1046	
1047	    if (elf_bits_ == 64) {
1048	        if (size < sizeof(Elf64_Ehdr)) return false;
1049	        const Elf64_Ehdr* ehdr = reinterpret_cast<const Elf64_Ehdr*>(data);
1050	        if (!ehdr->e_shoff || ehdr->e_shoff + (uint64_t)ehdr->e_shnum * sizeof(Elf64_Shdr) > size)
1051	            return false;
1052	        if (ehdr->e_shstrndx >= ehdr->e_shnum) return false;
1053	        const Elf64_Shdr* shdr = reinterpret_cast<const Elf64_Shdr*>(data + ehdr->e_shoff);
1054	        if (shdr[ehdr->e_shstrndx].sh_offset >= size) return false;
1055	        const char* shstr = reinterpret_cast<const char*>(data + shdr[ehdr->e_shstrndx].sh_offset);
1056	        locate(shstr, shdr, ehdr->e_shnum, sizeof(Elf64_Shdr));
1057	    } else {
1058	        if (size < sizeof(Elf32_Ehdr)) return false;
1059	        const Elf32_Ehdr* ehdr = reinterpret_cast<const Elf32_Ehdr*>(data);
1060	        if (!ehdr->e_shoff || ehdr->e_shoff + (uint64_t)ehdr->e_shnum * sizeof(Elf32_Shdr) > size)
1061	            return false;
1062	        if (ehdr->e_shstrndx >= ehdr->e_shnum) return false;
1063	        const Elf32_Shdr* shdr = reinterpret_cast<const Elf32_Shdr*>(data + ehdr->e_shoff);
1064	        if (shdr[ehdr->e_shstrndx].sh_offset >= size) return false;
1065	        const char* shstr = reinterpret_cast<const char*>(data + shdr[ehdr->e_shstrndx].sh_offset);
1066	        locate(shstr, shdr, ehdr->e_shnum, sizeof(Elf32_Shdr));
1067	    }
1068	
1069	    if (!debug_abbrev_data_ || !debug_info_data_) {
1070	        LOGD(".debug_abbrev/.debug_info sections not found in ELF\n");
1071	        return false;
1072	    }
1073	    LOGD("elf_bits=%d  .debug_abbrev=%lu  .debug_info=%lu"
1074	         "  .debug_str=%lu  .debug_str_offsets=%lu\n",
1075	         elf_bits_,
1076	         (unsigned long)debug_abbrev_size_, (unsigned long)debug_info_size_,
1077	         (unsigned long)debug_str_size_,    (unsigned long)debug_str_offsets_size_);
1078	    return true;
1079	}
1080	
1081	bool DwarfLoader::Init(const char* elf_path) {
1082	    map_.reset(MemoryMap::MmapFile(elf_path));
1083	    if (!map_) {
1084	        LOGD("cannot open %s\n", elf_path);
1085	        return false;
1086	    }
1087	    if (!LocateSections()) return false;
1088	    ParseAbbrevSection();
1089	    ParseInfoSection();
1090	    if (structs_.empty()) {
1091	        LOGD("no struct/class types extracted from %s\n"
1092	             "make sure the file is an unstripped debug build\n", elf_path);
1093	        return false;
1094	    }
1095	    return true;
1096	}
1097	
1098	std::unique_ptr<DwarfLoader> DwarfLoader::Load(const char* elf_path) {
1099	    auto loader = std::unique_ptr<DwarfLoader>(new DwarfLoader());
1100	    if (!loader->Init(elf_path)) return nullptr;
1101	    return loader;
1102	}
1103	
1104	void DwarfLoader::ForEachStruct(std::function<bool (const StructInfo&)> cb) const {
1105	    for (const StructInfo& si : structs_)
1106	        if (cb(si)) break;
1107	}
