27	uint64_t UnwindStack::GetUContext() {
28	    if (cur_uc_) return cur_uc_;
29	    ThreadInfo* thread = reinterpret_cast<ThreadInfo*>(GetThread());
30	    Register& regs = thread->GetRegs();
31	
32	    uint8_t __reserved[120 + 8];
33	    memset(&__reserved, 0x0, sizeof(__reserved));
34	
35	    api::MemoryRef sp = regs.sp;
36	    sp.Prepare(false);
37	    LoadBlock* block = sp.Block();
38	    if (!block) return cur_uc_;
39	
40	    try {
41	        api::MemoryRef uc = sp.Ptr() & CoreApi::GetVabitsMask();
42	        uc.checkCopyBlock(block);
43	        while(uc.Ptr() + sizeof(struct ucontext) < (block->vaddr() + block->size())) {
44	            struct ucontext* context = (struct ucontext*)uc.Real();
45	            if (block->virtualContains(context->uc_stack.ss_sp)
46	                    && context->uc_stack.ss_size <= block->memsz()
47	                    && context->uc_stack.ss_size >= CoreApi::GetPageSize()
48	                    && !(context->uc_stack.ss_size % CoreApi::GetPageSize())
49	                    // uc_link must 0
50	                    && context->uc_link == 0x0) {
51	                if (!memcmp(__reserved, context->__reserved, sizeof(__reserved))) {
52	                    cur_uc_ = uc.Ptr();
53	                    break;
54	                }
55	            }
56	            uc.MovePtr(8);
57	        }
58	    } catch(InvalidAddressException& e) {
59	        // do nothing
60	    }
61	    return cur_uc_;
62	}
63	
64	void UnwindStack::WalkStack() {
65	    ThreadInfo* thread = reinterpret_cast<ThreadInfo*>(GetThread());
66	    Register& regs = thread->GetRegs();
67	    FpBacktrace(regs);
68	
69	    api::MemoryRef uc = GetUContext();
70	    if (uc.Ptr()) {
71	        uc_num_ = cur_num_;
72	        struct ucontext* context = (struct ucontext*)uc.Real();
73	        Register uc_regs;
74	        memcpy(&uc_regs, &context->uc_mcontext.regs, sizeof(Register));
75	        FpBacktrace(uc_regs);
76	    }
77	}
78	
79	void UnwindStack::FpBacktrace(Register& regs) {
80	    try {
81	        cur_frame_fp_ = regs.fp;
82	        cur_frame_pc_ = regs.pc;
83	
84	        // FP CALLTRACE
85	        VisitFrame();
86	        LoadBlock* vdso = CoreApi::FindLoadBlock(CoreApi::FindAuxv(AT_SYSINFO_EHDR), false);
87	        cur_frame_pc_ = regs.lr;
88	        if (!vdso || !vdso->virtualContains(cur_frame_pc_))
89	            cur_frame_pc_ -= 0x4;
90	
91	        api::MemoryRef fp = cur_frame_fp_;
92	        fp.Prepare(false);
93	        LoadBlock* block = fp.Block();
94	        if (!block || (regs.lr != fp.value64Of(8))) {
95	            VisitFrame();
96	
97	            // skip lr frame
98	            std::unique_ptr<NativeFrame>& lr_frame = native_frames_[native_frames_.size() - 1];
99	            std::unique_ptr<NativeFrame>& pc_frame = native_frames_[native_frames_.size() - 2];
100	            std::string& lr_symbol = lr_frame->GetMethodSymbol();
101	            if ((lr_symbol.length() && lr_symbol == pc_frame->GetMethodSymbol())
102	                    || lr_frame->GetFramePc() == pc_frame->GetFramePc())
103	                native_frames_.pop_back();
104	        }
105	
106	    } catch(InvalidAddressException& e) {
107	        // do nothing
108	    }
109	
110	    OnlyFpBackStack(cur_frame_fp_);
111	}
112	
113	void UnwindStack::OnlyFpBackStack(uint64_t curfp) {
114	    try {
115	        LoadBlock* vdso = CoreApi::FindLoadBlock(CoreApi::FindAuxv(AT_SYSINFO_EHDR), false);
116	
117	        api::MemoryRef fp = curfp;
118	        fp.Prepare(false);
119	        LoadBlock* block = fp.Block();
120	        if (!block) return;
121	
122	        while (1) {
123	            cur_frame_pc_ = fp.value64Of(8);
124	            if (!vdso || !vdso->virtualContains(cur_frame_pc_))
125	                cur_frame_pc_ -= 0x4;
126	            cur_frame_fp_ = fp.value64Of();
127	
128	            if (cur_frame_fp_ <= fp.Ptr())
129	                break;
130	
131	            fp = cur_frame_fp_;
132	            fp.checkCopyBlock(block);
133	            if (block != fp.Block())
134	                break;
135	
136	            VisitFrame();
137	        }
138	    } catch(InvalidAddressException& e) {
139	        // do nothing
140	    }
141	}
142	
143	void UnwindStack::DumpContextRegister(const char* prefix) {
144	    api::MemoryRef uc = GetUContext();
145	    if (uc.Ptr()) {
146	        struct ucontext* context = (struct ucontext*)uc.Real();
147	        Register uc_regs;
148	        memcpy(&uc_regs, &context->uc_mcontext.regs, sizeof(Register));
149	        uc_regs.Dump(prefix);
150	    }
151	}
