27	class Block {
28	public:
29	    static constexpr int FLAG_X = (1 << 0);    /* Segment is executable */
30	    static constexpr int FLAG_W = (1 << 1);    /* Segment is writable */
31	    static constexpr int FLAG_R = (1 << 2);    /* Segment is readable */
32	
33	    static constexpr int OPT_READ_OR = (1 << 0);
34	    static constexpr int OPT_READ_MMAP = (1 << 1);
35	    static constexpr int OPT_READ_OVERLAY = (1 << 2);
36	    static constexpr int OPT_READ_ALL = OPT_READ_OR | OPT_READ_MMAP | OPT_READ_OVERLAY;
37	
38	    inline uint64_t vaddr() { return mVaddr; }
39	    inline uint64_t paddr() { return mPaddr; }
40	    inline uint32_t flags() { return mFlags; }
41	    inline uint64_t offset() { return mOffset; }
42	    inline uint64_t memsz() { return mMemSize; }
43	    inline uint64_t realSize() { return mFileSize; }
44	    inline uint64_t align() { return mAlign; }
45	    inline bool isValidBlock() { return !mTruncated && (mFileSize > 0); }
46	    inline uint64_t oraddr() { return mOriAddr; }
47	    inline bool isFake() { return mFake; }
48	    inline bool isTruncated() { return mTruncated; }
49	
50	    Block(uint32_t f, uint64_t off, uint64_t va, uint64_t pa,
51	            uint64_t filesz, uint64_t memsz, uint64_t align)
52	            : mFlags(f), mOffset(off), mVaddr(va), mPaddr(pa),
53	              mFileSize(filesz), mMemSize(memsz), mAlign(align),
54	              mOriAddr(0x0), mTruncated(false), mFake(false) {}
55	
56	    ~Block() {
57	        mOverlay.reset();
58	    }
59	    void setOriAddr(uint64_t addr) { if (isValidBlock()) mOriAddr = addr; }
60	    void setTruncated(bool truncated) { mTruncated = truncated; }
61	    void setFake(bool fake) { mFake = fake; }
62	
63	    inline std::string convertFlags() {
64	        std::string sb;
65	        if (flags() & FLAG_R) {
66	            sb.append("r");
67	        } else {
68	            sb.append("-");
69	        }
70	
71	        if (flags() & FLAG_W) {
72	            sb.append("w");
73	        } else {
74	            sb.append("-");
75	        }
76	
77	        if (flags() & FLAG_X) {
78	            sb.append("x");
79	        } else {
80	            sb.append("-");
81	        }
82	        return sb;
83	    }
84	
85	    virtual bool newOverlay() { return false; }
86	    virtual void setOverlay(uint64_t addr, void *buf, uint64_t size) {}
87	    virtual void removeOverlay() {}
88	    inline bool isOverlayBlock() { return mOverlay != nullptr; }
89	    inline void setOverlayMemoryMap(std::unique_ptr<MemoryMap>& map) { mOverlay = std::move(map); }
90	protected:
91	    std::unique_ptr<MemoryMap> mOverlay;
92	
93	private:
94	    //  program member
95	    uint32_t mFlags;
96	    uint64_t mOffset;
97	    uint64_t mVaddr;
98	    uint64_t mPaddr;
99	    uint64_t mFileSize;
100	    uint64_t mMemSize;
101	    uint64_t mAlign;
102	
103	    // Real memory addr
104	    uint64_t mOriAddr;
105	    bool mTruncated;
106	    bool mFake;
107	};
